#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int *S = (int*)malloc(n * sizeof(int));
        int *U = (int*)malloc(n * sizeof(int)); // T permutation, name changed to avoid clash
        for (int i = 0; i < n; ++i) scanf("%d", &S[i]);
        for (int i = 0; i < n; ++i) scanf("%d", &U[i]);
        char *P = (char*)malloc((n + 1) * sizeof(char));
        int diff = 0;
        for (int i = 0; i < n; ++i) {
            if (diff > 0) {
                P[i] = 'B';
                diff--;
            } else {
                P[i] = 'A';
                diff++;
            }
        }
        P[n] = '\0';
        printf("%s\n", P);
        free(S);
        free(U);
        free(P);
    }
    return 0;
}

