// COMPLETE, COMPILABLE C++ code
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        int n; cin>>n;
        vector<int> S(n), U(n);
        for(int &x: S) cin>>x;
        for(int &x: U) cin>>x;
        string P; P.reserve(n);
        int diff = 0;
        for(int i=0;i<n;++i){
            if(diff>0){
                P.push_back('B');
                --diff;
            }else{
                P.push_back('A');
                ++diff;
            }
        }
        cout<<P<<"\n";
    }
    return 0;
}
